let csrf=<?=json_encode(oneid_csrf_token())?>, purpose=<?=json_encode($purpose)?>, setupMode=<?=json_encode($setupMode)?>, enrollmentIntent=<?=json_encode($enrollmentIntent)?>, resetIntent=<?=json_encode($resetIntent)?>, successRedirect=<?=json_encode($successRedirect)?>, state={}; const api=<?=json_encode(APP_URL.'/lib/q_func.php')?>;
const messageBox=document.getElementById('message'),statusBox=document.getElementById('status'),setupBox=document.getElementById('setup'),resetBox=document.getElementById('reset'),resetReason=document.getElementById('resetReason'),bootstrapBox=document.getElementById('bootstrap'),challengeBox=document.getElementById('challengeBox'),disabledNotice=document.getElementById('disabledNotice');
function msg(t,ok=false){messageBox.innerHTML='<div class="msg '+(ok?'ok':'bad')+'"></div>';messageBox.firstChild.textContent=t||'Permintaan tidak berjaya.'}
async function post(action,data={}){let r=await fetch(api,{method:'POST',headers:{'X-CSRF-Token':csrf,'Accept':'application/json'},body:new URLSearchParams({_csrf_token:csrf,[action]:'1',...data})});let j=await r.json();if(!r.ok||j.status===0)throw j;if(j.csrf_token)csrf=j.csrf_token;return j}
async function load(){try{state=await post('admin_step_up_status',{purpose});if(state.grant_valid&&!setupMode){location.replace(successRedirect);return}statusBox.textContent=`Feature: ${state.feature_enabled?'ON':'OFF'} | E-mel: ${state.masked_email||'tiada'} | Authenticator: ${state.totp_available?'AKTIF':'belum didaftar'}`;authFactorTotp.disabled=!state.totp_available;authFactorEmail.disabled=!state.email_available;authFactor.value=resetIntent?'EMAIL_OTP':(state.preferred_factor==='TOTP'&&state.totp_available?'TOTP':'EMAIL_OTP');authFactor.disabled=false;chooseFactor.disabled=false;chooseFactor.textContent='Teruskan';const emailOnly=resetIntent||(!state.totp_available&&state.email_available);factorChoice.style.display=emailOnly?'none':'block';if(emailOnly){totpBox.classList.add('hidden');emailBox.classList.remove('hidden');emailHint.textContent='OTP akan dihantar ke '+(state.masked_email||'e-mel rasmi');factorIntro.textContent=resetIntent?'Reset Authenticator wajib disahkan menggunakan OTP e-mel.':(purpose==='SECURITY_CONFIGURATION_CHANGE'?'Sahkan melalui OTP e-mel untuk meneruskan pendaftaran Microsoft Authenticator dan memaparkan QR baharu.':'Microsoft Authenticator belum didaftarkan. Gunakan OTP e-mel untuk mengakses Administrator.')}else{factorIntro.textContent='Anda boleh memilih Microsoft Authenticator atau OTP melalui e-mel rasmi.'}setupBox.style.display=!resetIntent&&!state.totp_available&&(!state.feature_enabled||setupMode)?'block':'none';resetBox.classList.toggle('hidden',!(setupMode&&resetIntent&&state.totp_available));bootstrapBox.style.display=state.feature_enabled?'none':'block';challengeBox.style.display=state.feature_enabled&&!setupMode?'block':'none';disabledNotice.classList.toggle('hidden',state.feature_enabled);if(setupMode&&!state.totp_available){msg('Pengesahan keselamatan berjaya. Daftar Microsoft Authenticator baharu di bawah.',true)}if(setupMode&&resetIntent&&state.totp_available){msg('OTP e-mel disahkan. Sahkan reset faktor semasa.',true)}}catch(e){authFactor.disabled=true;chooseFactor.disabled=true;chooseFactor.textContent='Kaedah tidak tersedia';msg(e.code||e.error)}}
document.getElementById('chooseFactor').onclick=()=>{emailBox.classList.add('hidden');totpBox.classList.add('hidden');if(authFactor.value==='TOTP'){if(!state.totp_available){msg('Microsoft Authenticator belum tersedia.');return}totpBox.classList.remove('hidden')}else{emailHint.textContent='OTP akan dihantar ke '+(state.masked_email||'e-mel rasmi');emailBox.classList.remove('hidden')}};
let resendTimer=null;
function startResendCountdown(seconds){clearInterval(resendTimer);let remaining=Math.max(1,Number(seconds)||60);emailRequest.disabled=true;const tick=()=>{emailRequest.textContent=`Hantar semula (${remaining}s)`;remaining--;if(remaining<0){clearInterval(resendTimer);resendTimer=null;emailRequest.disabled=false;emailRequest.textContent='Hantar semula OTP e-mel'}};tick();resendTimer=setInterval(tick,1000)}
emailRequest.onclick=async()=>{try{emailRequest.disabled=true;emailRequest.textContent='Menghantar…';let j=await post('admin_step_up_request_email',{purpose});challengeId.value=j.challenge_id;startResendCountdown(j.resend_after_seconds);msg('OTP telah diterima oleh pelayan e-mel untuk '+j.masked_email+'. Semak Inbox, Junk atau Quarantine.',true)}catch(e){emailRequest.disabled=false;emailRequest.textContent='Hantar OTP e-mel';if(e.code==='STEP_UP_RESEND_COOLDOWN'){startResendCountdown(60);msg('OTP baru sahaja dihantar. Tunggu kira detik sebelum meminta kod baharu.')}else{msg(e.code||e.error)}}};
emailVerify.onclick=async()=>{try{await post('admin_step_up_verify_email',{purpose,challenge_id:challengeId.value,code:emailCode.value});location.href=resetIntent?<?=json_encode(APP_URL.'/page/admin-step-up?purpose=SECURITY_CONFIGURATION_CHANGE&setup=totp&intent=totp_reset')?>:(!state.totp_available&&purpose==='SECURITY_CONFIGURATION_CHANGE'?<?=json_encode(APP_URL.'/page/admin-step-up?purpose=SECURITY_CONFIGURATION_CHANGE&setup=totp&intent=totp_enroll')?>:successRedirect)}catch(e){const labels={STEP_UP_VERIFICATION_FAILED:'Kod OTP tidak sah. Gunakan kod daripada e-mel paling baharu dan pastikan semua 6 digit tepat.',STEP_UP_EXPIRED:'Kod OTP telah tamat tempoh. Minta kod baharu.',STEP_UP_REPLAYED:'Kod OTP ini telah digunakan atau digantikan. Minta kod baharu.'};msg(labels[e.code]||e.code||e.error)}};
totpVerify.onclick=async()=>{try{await post('admin_step_up_verify_totp',{purpose,code:totpCode.value});location.href=successRedirect}catch(e){msg(e.code||e.error)}};
enroll.onclick=async()=>{try{let j=await post('admin_totp_enroll',{current_password:currentPassword.value,device_label:deviceLabel.value});factorId.value=j.factor_id;secret.textContent=j.secret;otpUri.href=j.provisioning_uri;qr.src='admin-totp-qr?factor_id='+encodeURIComponent(j.factor_id);provision.classList.remove('hidden');msg('QR dijana. Sahkan dengan kod pertama.',true)}catch(e){msg(e.code||e.error)}};
document.getElementById('confirm').onclick=async()=>{try{await post('admin_totp_confirm',{factor_id:factorId.value,code:confirmCode.value});provision.classList.add('hidden');await load();msg('Microsoft Authenticator berjaya disahkan dan kini AKTIF.',true)}catch(e){msg(e.code||e.error)}};
document.getElementById('resetAuthenticator').onclick=()=>{let reason=resetReason.value.trim();if(reason.length<10){swal('Sebab reset diperlukan','Masukkan sebab reset sekurang-kurangnya 10 aksara.','warning');return}swal({title:'Reset Microsoft Authenticator?',text:'Faktor semasa akan direvoke dan tidak boleh digunakan lagi. Anda akan dibawa ke enrollment QR baharu.',type:'warning',showCancelButton:true,confirmButtonColor:'#b4233b',confirmButtonText:'Revoke dan daftar semula',cancelButtonText:'Batal',closeOnConfirm:false},async function(){try{await post('admin_totp_revoke',{factor_id:state.totp_factor_id,reason});swal({title:'Authenticator direvoke',text:'Teruskan untuk mendaftarkan Microsoft Authenticator baharu.',type:'success',confirmButtonText:'Teruskan',closeOnConfirm:false},function(){location.replace(<?=json_encode(APP_URL.'/page/admin-step-up?purpose=SECURITY_CONFIGURATION_CHANGE&setup=totp&intent=totp_enroll')?>)})}catch(e){swal('Reset gagal',e.code||e.error||'Permintaan reset tidak dapat diproses.','error')}})};
document.getElementById('enable').onclick=async()=>{try{await post('admin_2fa_bootstrap_enable',{current_password:document.getElementById('bootstrapPassword').value,configuration_version:state.configuration_version,change_reason:document.getElementById('changeReason').value,change_id:document.getElementById('changeId').value,typed_confirmation:document.getElementById('typed').value});msg('Admin 2FA diaktifkan.',true);await load()}catch(e){const labels={BOOTSTRAP_CHANGE_ID_INVALID:'Change ID tidak tepat.',BOOTSTRAP_TYPED_CONFIRMATION_INVALID:'Typed confirmation mesti tepat: ENABLE ADMIN 2FA',BOOTSTRAP_REASON_INVALID:'Sebab perubahan mesti antara 10 hingga 500 aksara.',BOOTSTRAP_IP_INVALID:'Alamat IP request tidak sah.',BOOTSTRAP_PASSWORD_INVALID:'Kata laluan semasa tidak sah.',BOOTSTRAP_FACTORS_REQUIRED:'E-mel sah dan Authenticator aktif diperlukan.',BOOTSTRAP_CONFIGURATION_STALE:'Configuration telah berubah. Refresh halaman dan cuba semula.'};msg(labels[e.code]||e.code||e.error)}};load();
</script></body></html>
